Component({
  properties: {
    type: {
      type: Number,
      value: 1
    },
    // 是否显示面板指示点
    indicatorDots: {
      type: Boolean,
      value: false
    },
    // 是否自动切换
    autoplay: {
      type: Boolean,
      value: false
    },
    // 自动切换时间间隔
    interval: {
      type: Number,
      value: 4000
    },
    // 滑动动画时长
    duration: {
      type: Number,
      value: 500
    },
    imgUrls: {
      type: Array,
      value: []
    },
    // 覆盖在轮播图上的图片
    coverImg: {
      type: String,
      value: ''
    },
    border: {
      type: Boolean,
      value: false
    }
  },
  methods: {
    clickSwiperItem(e) {
      const href = e.currentTarget.dataset.href
      if (!href) {
        return
      }
      this.triggerEvent('dealPath', {
        data: href
      })
    }
  },

})
